/**
 * Theosis Library — Client-side search
 * Searches across translation entries on the library index page.
 * Also loads search-index.json for full-text search of published translations.
 */

(function () {
  'use strict';

  var searchInput = document.getElementById('search-input');
  var searchInfo = document.getElementById('search-results-info');
  var textItems = document.querySelectorAll('.text-item');
  var searchIndex = null;

  // Try to load the full-text search index (generated by build_index.py)
  fetch('/search-index.json')
    .then(function (res) {
      if (res.ok) return res.json();
      return null;
    })
    .then(function (data) {
      searchIndex = data;
    })
    .catch(function () {
      // No search index available yet — page-level search still works
    });

  if (!searchInput || !textItems.length) return;

  searchInput.addEventListener('input', function () {
    var query = this.value.toLowerCase().trim();

    if (!query) {
      // Show all items
      for (var i = 0; i < textItems.length; i++) {
        textItems[i].style.display = '';
      }
      searchInfo.style.display = 'none';
      return;
    }

    var visible = 0;
    var terms = query.split(/\s+/);

    for (var i = 0; i < textItems.length; i++) {
      var item = textItems[i];
      var author = (item.getAttribute('data-author') || '').toLowerCase();
      var title = (item.getAttribute('data-title') || '').toLowerCase();
      var themes = (item.getAttribute('data-themes') || '').toLowerCase();
      var description = (item.querySelector('.text-description') || {}).textContent || '';
      description = description.toLowerCase();

      var searchable = author + ' ' + title + ' ' + themes + ' ' + description;

      var match = terms.every(function (term) {
        return searchable.indexOf(term) !== -1;
      });

      if (match) {
        item.style.display = '';
        visible++;
      } else {
        item.style.display = 'none';
      }
    }

    searchInfo.textContent = visible + ' text' + (visible !== 1 ? 's' : '') + ' matching "' + this.value + '"';
    searchInfo.style.display = 'block';
  });
})();
